effect.script:
function animate(env,el,p,pprev) {

    let cursor = p.cursor;
    let cursorChar = "";
    if( cursor==0 ) {
        cursorChar = "";
    } else if( cursor==1 ) {
        cursorChar = "_";
    } else if( cursor==2 ) {
        cursorChar = "█";
    } else if( cursor==3 ) {
        cursorChar = "▌";
    } else if( cursor==4 ) {
        cursorChar = "▁";
    } else if( cursor==5 ) {
        cursorChar = "▏";
    } else if( cursor==6 ) {
        cursorChar = "▕";
    } else if( cursor==7 ) {
        cursorChar = "▯";
    } else if( cursor==8 ) {
        cursorChar = "▎";
    }

    if( p.blink ) {

        if( Math.round(el.text.length * p.start) == Math.round(el.text.length * pprev.start) &&
            Math.round(el.text.length * p.end) == Math.round(el.text.length * pprev.end) ) {

            if( (env.time * env.duration * 2) % 2 > 1 ) cursorChar = "";

        }
    }

    el.text = el.text.slice( Math.round(el.text.length * p.start), Math.round(el.text.length * p.end)) + cursorChar;

    return el;
}
